19|// Complex number structure
20|struct complex_t {
21|    fixed_t re;
22|    fixed_t im;
23|    
24|    complex_t() : re(0), im(0) {}
25|    complex_t(fixed_t r, fixed_t i) : re(r), im(i) {}
26|};
