28|// Complex arithmetic helper functions
29|inline complex_t complex_add(const complex_t& a, const complex_t& b) {
30|    return complex_t(a.re + b.re, a.im + b.im);
31|}
32|
33|inline complex_t complex_sub(const complex_t& a, const complex_t& b) {
34|    return complex_t(a.re - b.re, a.im - b.im);
