47|inline fixed_t complex_abs(const complex_t& a) {
48|    // |z| = sqrt(re^2 + im^2)
49|    fixed_t re_sq = a.re * a.re;
50|    fixed_t im_sq = a.im * a.im;
51|    fixed_t sum = re_sq + im_sq;
52|    return hls::sqrt(sum);
53|}
