 18|// Jacobi eigenvalue decomposition kernel
 19|void kernel_top(
 20|    const ap_int<TOTAL_BITS> matrix_real_in[MATRIX_SIZE * MATRIX_SIZE],
 21|    const ap_int<TOTAL_BITS> matrix_imag_in[MATRIX_SIZE * MATRIX_SIZE],
 22|    ap_int<TOTAL_BITS> eigenvalues_real_out[MATRIX_SIZE],
 23|    ap_int<TOTAL_BITS> eigenvectors_real_out[MATRIX_SIZE * MATRIX_SIZE],
 24|    ap_int<TOTAL_BITS> eigenvectors_imag_out[MATRIX_SIZE * MATRIX_SIZE],
 25|    ap_uint<12>& iter_count,
 26|    ap_uint<32>& cycles
 27|) {
 28|    // Interface pragmas
 29|    #pragma HLS INTERFACE mode=m_axi port=matrix_real_in bundle=gmem0 depth=100
 30|    #pragma HLS INTERFACE mode=m_axi port=matrix_imag_in bundle=gmem1 depth=100
 31|    #pragma HLS INTERFACE mode=m_axi port=eigenvalues_real_out bundle=gmem2 depth=10
 32|    #pragma HLS INTERFACE mode=m_axi port=eigenvectors_real_out bundle=gmem3 depth=100
 33|    #pragma HLS INTERFACE mode=m_axi port=eigenvectors_imag_out bundle=gmem4 depth=100
 34|    #pragma HLS INTERFACE mode=s_axilite port=iter_count
 35|    #pragma HLS INTERFACE mode=s_axilite port=cycles
 36|    #pragma HLS INTERFACE mode=s_axilite port=return
 37|    
 38|    // Local matrix A (working copy)
 39|    complex_t A[MATRIX_SIZE][MATRIX_SIZE];
 40|    #pragma HLS ARRAY_PARTITION variable=A dim=0 type=complete
 41|    
 42|    // Local eigenvector matrix V (initialized to identity)
 43|    complex_t V[MATRIX_SIZE][MATRIX_SIZE];
 44|    #pragma HLS ARRAY_PARTITION variable=V dim=0 type=complete
 45|    
 46|    // Load input matrix and initialize V to identity
 47|    LOAD_MATRIX_LOOP_I: for (int i = 0; i < MATRIX_SIZE; i++) {
 48|        LOAD_MATRIX_LOOP_J: for (int j = 0; j < MATRIX_SIZE; j++) {
 49|            #pragma HLS PIPELINE II=1
 50|            int idx = i * MATRIX_SIZE + j;
 51|            A[i][j].re = int_to_fixed(matrix_real_in[idx]);
 52|            A[i][j].im = int_to_fixed(matrix_imag_in[idx]);
 53|            
 54|            // Initialize V to identity
 55|            if (i == j) {
 56|                V[i][j].re = 1.0;
 57|                V[i][j].im = 0.0;
 58|            } else {
 59|                V[i][j].re = 0.0;
 60|                V[i][j].im = 0.0;
 61|            }
 62|        }
 63|    }
 64|    
 65|    ap_uint<32> cycle_count = 0;
 66|    
 67|    // Jacobi iteration loop
 68|    JACOBI_ITERATION: for (int z = 0; z < MAX_ITERATIONS; z++) {
 69|        // Find maximum off-diagonal element
 70|        fixed_t off_diag_max = 0;
 71|        int p = 0, q = 1;
 72|        
 73|        FIND_MAX_I: for (int i = 0; i < MATRIX_SIZE; i++) {
 74|            FIND_MAX_J: for (int j = i + 1; j < MATRIX_SIZE; j++) {
 75|                #pragma HLS PIPELINE II=1
 76|                fixed_t abs_aij = complex_abs(A[i][j]);
 77|                if (abs_aij > off_diag_max) {
 78|                    off_diag_max = abs_aij;
 79|                    p = i;
 80|                    q = j;
 81|                }
 82|            }
 83|        }
 84|        
 85|        cycle_count += MATRIX_SIZE * (MATRIX_SIZE - 1) / 2;
 86|        
 87|        // Check convergence
 88|        if (off_diag_max < CONVERGENCE_THRESHOLD) {
 89|            iter_count = z;
 90|            break;
 91|        }
 92|        
 93|        // Extract pivot elements
 94|        complex_t a_pp = A[p][p];
 95|        complex_t a_qq = A[q][q];
 96|        complex_t a_pq = A[p][q];
 97|        
 98|        // Compute rotation angles
 99|        // theta = 0.5 * arctan(2 * |a_pq| / (a_pp - a_qq))
100|        fixed_t abs_apq = complex_abs(a_pq);
101|        fixed_t diff = a_pp.re - a_qq.re;  // Diagonal elements are real for Hermitian
102|        
103|        fixed_t theta;
104|        if (hls::abs(diff) < fixed_t(0.0001)) {
105|            // Avoid division by zero
106|            theta = fixed_t(0.785398163);  // pi/4 in radians
107|        } else {
108|            fixed_t ratio = (2 * abs_apq) / diff;
109|            theta = 0.5 * hls::atan(ratio);
110|        }
111|        
112|        fixed_t phi = -complex_angle(a_pq);
113|        
114|        // Compute sin/cos values
115|        fixed_t cos_theta = hls::cos(theta);
116|        fixed_t sin_theta = hls::sin(theta);
117|        
118|        // Compute e^(i*phi) and e^(-i*phi)
119|        fixed_t cos_phi = hls::cos(phi);
120|        fixed_t sin_phi = hls::sin(phi);
121|        complex_t exp_iphi(cos_phi, sin_phi);
122|        complex_t exp_minus_iphi(cos_phi, -sin_phi);
123|        
124|        // Build rotation matrix U (only non-trivial elements)
125|        // U[p,p] = cos(theta)
126|        // U[p,q] = sin(theta) * exp(-i*phi)
127|        // U[q,p] = sin(theta) * exp(i*phi)
128|        // U[q,q] = -cos(theta)  // Note: reference has this, though it may be incorrect
129|        
130|        complex_t U_pp(cos_theta, 0);
131|        complex_t U_pq = complex_t(sin_theta, 0);
132|        U_pq = complex_mul(U_pq, exp_minus_iphi);
133|        complex_t U_qp = complex_t(sin_theta, 0);
134|        U_qp = complex_mul(U_qp, exp_iphi);
135|        complex_t U_qq(-cos_theta, 0);
136|        
137|        // Temporary storage for row/column updates
138|        complex_t temp_A_row_p[MATRIX_SIZE];
139|        complex_t temp_A_row_q[MATRIX_SIZE];
140|        complex_t temp_A_col_p[MATRIX_SIZE];
141|        complex_t temp_A_col_q[MATRIX_SIZE];
142|        
143|        #pragma HLS ARRAY_PARTITION variable=temp_A_row_p type=complete
144|        #pragma HLS ARRAY_PARTITION variable=temp_A_row_q type=complete
145|        #pragma HLS ARRAY_PARTITION variable=temp_A_col_p type=complete
146|        #pragma HLS ARRAY_PARTITION variable=temp_A_col_q type=complete
147|        
148|        // Apply transformation A = U^H @ A @ U
149|        // Step 1: Compute A' = A @ U (right multiplication)
150|        // Only columns p and q are affected
151|        UPDATE_A_RIGHT: for (int i = 0; i < MATRIX_SIZE; i++) {
152|            #pragma HLS PIPELINE II=1
153|            complex_t a_ip = A[i][p];
154|            complex_t a_iq = A[i][q];
155|            
156|            // new A[i,p] = a_ip * U[p,p] + a_iq * U[q,p]
157|            temp_A_col_p[i] = complex_add(
158|                complex_mul(a_ip, U_pp),
159|                complex_mul(a_iq, U_qp)
160|            );
161|            
162|            // new A[i,q] = a_ip * U[p,q] + a_iq * U[q,q]
163|            temp_A_col_q[i] = complex_add(
164|                complex_mul(a_ip, U_pq),
165|                complex_mul(a_iq, U_qq)
166|            );
167|        }
168|        
169|        // Write back columns
170|        UPDATE_A_WRITE_COL: for (int i = 0; i < MATRIX_SIZE; i++) {
171|            #pragma HLS UNROLL
172|            A[i][p] = temp_A_col_p[i];
173|            A[i][q] = temp_A_col_q[i];
174|        }
175|        
176|        cycle_count += MATRIX_SIZE * 2;
177|        
178|        // Step 2: Compute A = U^H @ A' (left multiplication)
179|        // Only rows p and q are affected
180|        UPDATE_A_LEFT: for (int j = 0; j < MATRIX_SIZE; j++) {
181|            #pragma HLS PIPELINE II=1
182|            complex_t a_pj = A[p][j];
183|            complex_t a_qj = A[q][j];
184|            
185|            // new A[p,j] = conj(U[p,p]) * a_pj + conj(U[p,q]) * a_qj
186|            temp_A_row_p[j] = complex_add(
187|                complex_mul(complex_conj(U_pp), a_pj),
188|                complex_mul(complex_conj(U_pq), a_qj)
189|            );
190|            
191|            // new A[q,j] = conj(U[q,p]) * a_pj + conj(U[q,q]) * a_qj
192|            temp_A_row_q[j] = complex_add(
193|                complex_mul(complex_conj(U_qp), a_pj),
194|                complex_mul(complex_conj(U_qq), a_qj)
195|            );
196|        }
197|        
198|        // Write back rows
199|        UPDATE_A_WRITE_ROW: for (int j = 0; j < MATRIX_SIZE; j++) {
200|            #pragma HLS UNROLL
201|            A[p][j] = temp_A_row_p[j];
202|            A[q][j] = temp_A_row_q[j];
203|        }
204|        
205|        // Explicitly zero out the off-diagonal elements
206|        A[p][q].re = 0;
207|        A[p][q].im = 0;
208|        A[q][p].re = 0;
209|        A[q][p].im = 0;
210|        
211|        cycle_count += MATRIX_SIZE * 2;
212|        
213|        // Update eigenvector matrix V = V @ U
214|        // Only columns p and q are affected
215|        complex_t temp_V_col_p[MATRIX_SIZE];
216|        complex_t temp_V_col_q[MATRIX_SIZE];
217|        #pragma HLS ARRAY_PARTITION variable=temp_V_col_p type=complete
218|        #pragma HLS ARRAY_PARTITION variable=temp_V_col_q type=complete
219|        
220|        UPDATE_V: for (int i = 0; i < MATRIX_SIZE; i++) {
221|            #pragma HLS PIPELINE II=1
222|            complex_t v_ip = V[i][p];
223|            complex_t v_iq = V[i][q];
224|            
225|            // new V[i,p] = v_ip * U[p,p] + v_iq * U[q,p]
226|            temp_V_col_p[i] = complex_add(
227|                complex_mul(v_ip, U_pp),
228|                complex_mul(v_iq, U_qp)
229|            );
230|            
231|            // new V[i,q] = v_ip * U[p,q] + v_iq * U[q,q]
232|            temp_V_col_q[i] = complex_add(
233|                complex_mul(v_ip, U_pq),
234|                complex_mul(v_iq, U_qq)
235|            );
236|        }
237|        
238|        // Write back columns
239|        UPDATE_V_WRITE: for (int i = 0; i < MATRIX_SIZE; i++) {
240|            #pragma HLS UNROLL
241|            V[i][p] = temp_V_col_p[i];
242|            V[i][q] = temp_V_col_q[i];
243|        }
244|        
245|        cycle_count += MATRIX_SIZE * 2;
246|        
247|        // Update iteration count
248|        iter_count = z + 1;
249|    }
250|    
251|    // Extract eigenvalues (diagonal of A)
252|    EXTRACT_EIGENVALUES: for (int i = 0; i < MATRIX_SIZE; i++) {
253|        #pragma HLS PIPELINE II=1
254|        eigenvalues_real_out[i] = fixed_to_int(A[i][i].re);
255|    }
256|    
257|    // Write eigenvectors
258|    WRITE_EIGENVECTORS_I: for (int i = 0; i < MATRIX_SIZE; i++) {
259|        WRITE_EIGENVECTORS_J: for (int j = 0; j < MATRIX_SIZE; j++) {
260|            #pragma HLS PIPELINE II=1
261|            int idx = i * MATRIX_SIZE + j;
262|            eigenvectors_real_out[idx] = fixed_to_int(V[i][j].re);
263|            eigenvectors_imag_out[idx] = fixed_to_int(V[i][j].im);
264|        }
265|    }
266|    
267|    cycles = cycle_count;
268|}

