  9|// Helper to compute rotation matrix and apply Jacobi rotation
 10|void apply_jacobi_rotation(
 11|    complex_t A[MATRIX_SIZE][MATRIX_SIZE],
 12|    complex_t V[MATRIX_SIZE][MATRIX_SIZE],
 13|    int p, int q
 14|) {
 15|    // Get matrix elements
 16|    complex_t a_pp = A[p][p];
 17|    complex_t a_qq = A[q][q];
 18|    complex_t a_pq = A[p][q];
 19|    
 20|    // Hermitian matrices have real diagonal elements
 21|    fixed_t a_pp_real = a_pp.re;
 22|    fixed_t a_qq_real = a_qq.re;
 23|    
 24|    // Calculate rotation angle theta
 25|    fixed_t abs_a_pq = complex_abs(a_pq);
 26|    fixed_t denom = a_pp_real - a_qq_real;
 27|    
 28|    fixed_t theta;
 29|    if (hls::abs(denom) < fixed_t(1e-10)) {
 30|        theta = fixed_t(0.7853981633974483); // pi/4
 31|    } else {
 32|        theta = fixed_t(0.5) * hls::atan((fixed_t(2.0) * abs_a_pq) / denom);
 33|    }
 34|    
 35|    // Calculate phase angle phi
 36|    fixed_t phi = -complex_angle(a_pq);
 37|    
 38|    // Compute rotation matrix elements
 39|    fixed_t cos_theta = hls::cos(theta);
 40|    fixed_t sin_theta = hls::sin(theta);
 41|    fixed_t cos_phi = hls::cos(phi);
 42|    fixed_t sin_phi = hls::sin(phi);
 43|    
 44|    // U[p,p] = cos(theta)
 45|    complex_t u_pp(cos_theta, fixed_t(0));
 46|    // U[p,q] = sin(theta) * exp(-i*phi) = sin(theta) * (cos(phi) - i*sin(phi))
 47|    complex_t u_pq(sin_theta * cos_phi, -sin_theta * sin_phi);
 48|    // U[q,p] = sin(theta) * exp(i*phi) = sin(theta) * (cos(phi) + i*sin(phi))
 49|    complex_t u_qp(sin_theta * cos_phi, sin_theta * sin_phi);
 50|    // U[q,q] = cos(theta) (corrected from reference bug)
 51|    complex_t u_qq(cos_theta, fixed_t(0));
 52|    
 53|    // Temporary storage for transformed rows/cols
 54|    complex_t A_temp[MATRIX_SIZE][MATRIX_SIZE];
 55|    complex_t V_temp[MATRIX_SIZE][MATRIX_SIZE];
 56|    
 57|    // Copy A to A_temp
 58|    COPY_A_LOOP_I: for (int i = 0; i < MATRIX_SIZE; i++) {
 59|        COPY_A_LOOP_J: for (int j = 0; j < MATRIX_SIZE; j++) {
 60|            #pragma HLS PIPELINE II=1
 61|            A_temp[i][j] = A[i][j];
 62|        }
 63|    }
 64|    
 65|    // Apply left multiplication: A = U^H @ A
 66|    // Only rows p and q are affected
 67|    LEFT_MUL_COL: for (int j = 0; j < MATRIX_SIZE; j++) {
 68|        #pragma HLS PIPELINE II=1
 69|        complex_t a_pj = A_temp[p][j];
 70|        complex_t a_qj = A_temp[q][j];
 71|        
 72|        // New row p = conj(u_pp) * old_row_p + conj(u_qp) * old_row_q
 73|        complex_t u_pp_conj = complex_conj(u_pp);
 74|        complex_t u_qp_conj = complex_conj(u_qp);
 75|        A[p][j] = complex_add(complex_mul(u_pp_conj, a_pj), complex_mul(u_qp_conj, a_qj));
 76|        
 77|        // New row q = conj(u_pq) * old_row_p + conj(u_qq) * old_row_q
 78|        complex_t u_pq_conj = complex_conj(u_pq);
 79|        complex_t u_qq_conj = complex_conj(u_qq);
 80|        A[q][j] = complex_add(complex_mul(u_pq_conj, a_pj), complex_mul(u_qq_conj, a_qj));
 81|    }
 82|    
 83|    // Copy updated A to A_temp for right multiplication
 84|    COPY_A2_LOOP_I: for (int i = 0; i < MATRIX_SIZE; i++) {
 85|        COPY_A2_LOOP_J: for (int j = 0; j < MATRIX_SIZE; j++) {
 86|            #pragma HLS PIPELINE II=1
 87|            A_temp[i][j] = A[i][j];
 88|        }
 89|    }
 90|    
 91|    // Apply right multiplication: A = A @ U
 92|    // Only columns p and q are affected
 93|    RIGHT_MUL_ROW: for (int i = 0; i < MATRIX_SIZE; i++) {
 94|        #pragma HLS PIPELINE II=1
 95|        complex_t a_ip = A_temp[i][p];
 96|        complex_t a_iq = A_temp[i][q];
 97|        
 98|        // New col p = old_col_p * u_pp + old_col_q * u_qp
 99|        A[i][p] = complex_add(complex_mul(a_ip, u_pp), complex_mul(a_iq, u_qp));
100|        
101|        // New col q = old_col_p * u_pq + old_col_q * u_qq
102|        A[i][q] = complex_add(complex_mul(a_ip, u_pq), complex_mul(a_iq, u_qq));
103|    }
104|    
105|    // Zero out off-diagonal elements (p,q) and (q,p)
106|    A[p][q].re = fixed_t(0);
107|    A[p][q].im = fixed_t(0);
108|    A[q][p].re = fixed_t(0);
109|    A[q][p].im = fixed_t(0);
110|    
111|    // Update eigenvector matrix: V = V @ U
112|    // Copy V to V_temp
113|    COPY_V_LOOP_I: for (int i = 0; i < MATRIX_SIZE; i++) {
114|        COPY_V_LOOP_J: for (int j = 0; j < MATRIX_SIZE; j++) {
115|            #pragma HLS PIPELINE II=1
116|            V_temp[i][j] = V[i][j];
117|        }
118|    }
119|    
120|    // Update columns p and q of V
121|    UPDATE_V_ROW: for (int i = 0; i < MATRIX_SIZE; i++) {
122|        #pragma HLS PIPELINE II=1
123|        complex_t v_ip = V_temp[i][p];
124|        complex_t v_iq = V_temp[i][q];
125|        
126|        // New col p = old_col_p * u_pp + old_col_q * u_qp
127|        V[i][p] = complex_add(complex_mul(v_ip, u_pp), complex_mul(v_iq, u_qp));
128|        
129|        // New col q = old_col_p * u_pq + old_col_q * u_qq
130|        V[i][q] = complex_add(complex_mul(v_ip, u_pq), complex_mul(v_iq, u_qq));
131|    }
