134|void kernel_top(
135|    const fixed_t matrix_real_in[MATRIX_ELEMENTS],
136|    const fixed_t matrix_imag_in[MATRIX_ELEMENTS],
137|    fixed_t eigenvalues_real_out[MATRIX_SIZE],
138|    fixed_t eigenvalues_imag_out[MATRIX_SIZE],
139|    fixed_t eigenvectors_real_out[MATRIX_ELEMENTS],
140|    fixed_t eigenvectors_imag_out[MATRIX_ELEMENTS],
141|    int &iter_count,
142|    int &cycles
143|) {
144|    #pragma HLS INTERFACE mode=m_axi port=matrix_real_in bundle=gmem0
145|    #pragma HLS INTERFACE mode=m_axi port=matrix_imag_in bundle=gmem1
146|    #pragma HLS INTERFACE mode=m_axi port=eigenvalues_real_out bundle=gmem2
147|    #pragma HLS INTERFACE mode=m_axi port=eigenvalues_imag_out bundle=gmem3
148|    #pragma HLS INTERFACE mode=m_axi port=eigenvectors_real_out bundle=gmem4
149|    #pragma HLS INTERFACE mode=m_axi port=eigenvectors_imag_out bundle=gmem5
150|    #pragma HLS INTERFACE mode=s_axilite port=iter_count
151|    #pragma HLS INTERFACE mode=s_axilite port=cycles
152|    #pragma HLS INTERFACE mode=s_axilite port=return
153|    
154|    // Local storage for matrices
155|    complex_t A[MATRIX_SIZE][MATRIX_SIZE];
156|    complex_t V[MATRIX_SIZE][MATRIX_SIZE];
157|    
158|    #pragma HLS ARRAY_PARTITION variable=A dim=0 complete
159|    #pragma HLS ARRAY_PARTITION variable=V dim=0 complete
160|    
161|    // Load input matrix
162|    LOAD_MATRIX_I: for (int i = 0; i < MATRIX_SIZE; i++) {
163|        LOAD_MATRIX_J: for (int j = 0; j < MATRIX_SIZE; j++) {
164|            #pragma HLS PIPELINE II=1
165|            int idx = mat_idx(i, j);
166|            A[i][j].re = matrix_real_in[idx];
167|            A[i][j].im = matrix_imag_in[idx];
168|        }
169|    }
170|    
171|    // Initialize eigenvector matrix to identity
172|    INIT_V_I: for (int i = 0; i < MATRIX_SIZE; i++) {
173|        INIT_V_J: for (int j = 0; j < MATRIX_SIZE; j++) {
174|            #pragma HLS PIPELINE II=1
175|            if (i == j) {
176|                V[i][j].re = fixed_t(1.0);
177|                V[i][j].im = fixed_t(0);
178|            } else {
179|                V[i][j].re = fixed_t(0);
180|                V[i][j].im = fixed_t(0);
181|            }
182|        }
183|    }
184|    
185|    int iteration = 0;
186|    
187|    // Jacobi iteration loop
188|    JACOBI_ITER: for (int z = 0; z < MAX_ITERATIONS; z++) {
189|        // Find maximum off-diagonal element
190|        fixed_t off_diag_max = fixed_t(0);
191|        int max_p = 0;
192|        int max_q = 1;
193|        
194|        FIND_MAX_I: for (int i = 0; i < MATRIX_SIZE; i++) {
195|            FIND_MAX_J: for (int j = i + 1; j < MATRIX_SIZE; j++) {
196|                #pragma HLS PIPELINE II=1
197|                fixed_t abs_val = complex_abs(A[i][j]);
198|                if (abs_val > off_diag_max) {
199|                    off_diag_max = abs_val;
200|                    max_p = i;
201|                    max_q = j;
202|                }
203|            }
204|        }
205|        
206|        iteration = z;
207|        
208|        // Check convergence
209|        if (off_diag_max < fixed_t(CONVERGENCE_THRESHOLD)) {
210|            break;
211|        }
212|        
213|        // Apply Jacobi rotation
214|        apply_jacobi_rotation(A, V, max_p, max_q);
215|    }
216|    
217|    // Extract eigenvalues (diagonal of A) and write outputs
218|    WRITE_EIGENVALS: for (int i = 0; i < MATRIX_SIZE; i++) {
219|        #pragma HLS PIPELINE II=1
220|        eigenvalues_real_out[i] = A[i][i].re;
221|        eigenvalues_imag_out[i] = A[i][i].im;
222|    }
223|    
224|    // Write eigenvector matrix
225|    WRITE_EIGENVECS_I: for (int i = 0; i < MATRIX_SIZE; i++) {
226|        WRITE_EIGENVECS_J: for (int j = 0; j < MATRIX_SIZE; j++) {
227|            #pragma HLS PIPELINE II=1
228|            int idx = mat_idx(i, j);
229|            eigenvectors_real_out[idx] = V[i][j].re;
230|            eigenvectors_imag_out[idx] = V[i][j].im;
231|        }
232|    }
233|    
234|    // Set output metadata
235|    iter_count = iteration + 1;
236|    cycles = 0; // Will be measured by testbench
237|}

