 8|// Project configuration
 9|#define MATRIX_SIZE 10
10|#define TOTAL_BITS 46
11|#define FRAC_BITS 14
12|#define MAX_ITERATIONS 2000
13|#define CONVERGENCE_THRESHOLD 1e-8
