15|// Total matrix elements
16|#define MATRIX_ELEMENTS (MATRIX_SIZE * MATRIX_SIZE)
17|
18|// Fixed-point type for matrix elements
19|// Using Q46.14 format (46 total bits, 14 fractional bits)
20|typedef ap_fixed<TOTAL_BITS, TOTAL_BITS - FRAC_BITS, AP_RND, AP_SAT> fixed_t;
21|
22|// Complex number structure
23|struct complex_t {
24|    fixed_t re;
25|    fixed_t im;
26|    
27|    complex_t() : re(0), im(0) {}
28|    complex_t(fixed_t r, fixed_t i) : re(r), im(i) {}
29|};
