31|// Complex arithmetic operations
32|inline complex_t complex_add(complex_t a, complex_t b) {
33|    complex_t result;
34|    result.re = a.re + b.re;
35|    result.im = a.im + b.im;
36|    return result;
37|}
38|
39|inline complex_t complex_sub(complex_t a, complex_t b) {
40|    complex_t result;
41|    result.re = a.re - b.re;
42|    result.im = a.im - b.im;
43|    return result;
44|}
45|
46|inline complex_t complex_mul(complex_t a, complex_t b) {
47|    complex_t result;
48|    // (a + bi)(c + di) = (ac - bd) + (ad + bc)i
49|    result.re = a.re * b.re - a.im * b.im;
50|    result.im = a.re * b.im + a.im * b.re;
51|    return result;
52|}
53|
54|inline complex_t complex_conj(complex_t a) {
55|    complex_t result;
56|    result.re = a.re;
57|    result.im = -a.im;
58|    return result;
59|}
60|
61|inline fixed_t complex_abs(complex_t a) {
62|    // |a + bi| = sqrt(a^2 + b^2)
63|    fixed_t re2 = a.re * a.re;
64|    fixed_t im2 = a.im * a.im;
65|    fixed_t sum = re2 + im2;
66|    return hls::sqrt(sum);
67|}
68|
69|inline fixed_t complex_angle(complex_t a) {
70|    // angle = atan2(im, re)
71|    return hls::atan2(a.im, a.re);
72|}
