 18|// Matrix multiplication: C = A * B (both complex)
 19|static void matrix_mult(
 20|    complex_t A[MATRIX_SIZE][MATRIX_SIZE],
 21|    complex_t B[MATRIX_SIZE][MATRIX_SIZE],
 22|    complex_t C[MATRIX_SIZE][MATRIX_SIZE]
 23|) {
 24|    #pragma HLS INLINE off
 25|    
 26|    // Initialize output
 27|    for (int i = 0; i < MATRIX_SIZE; i++) {
 28|        for (int j = 0; j < MATRIX_SIZE; j++) {
 29|            #pragma HLS PIPELINE II=1
 30|            C[i][j].re = 0;
 31|            C[i][j].im = 0;
 32|        }
 33|    }
 34|    
 35|    // Multiply
 36|    for (int i = 0; i < MATRIX_SIZE; i++) {
 37|        for (int j = 0; j < MATRIX_SIZE; j++) {
 38|            for (int k = 0; k < MATRIX_SIZE; k++) {
 39|                #pragma HLS PIPELINE II=1
 40|                complex_t prod = complex_mult(A[i][k], B[k][j]);
 41|                C[i][j] = complex_add(C[i][j], prod);
 42|            }
 43|        }
 44|    }
 45|}
 46|
 47|// Apply rotation: A_new = U^H * A * U
 48|static void apply_rotation(
 49|    complex_t A[MATRIX_SIZE][MATRIX_SIZE],
 50|    complex_t U[MATRIX_SIZE][MATRIX_SIZE],
 51|    complex_t temp[MATRIX_SIZE][MATRIX_SIZE],
 52|    complex_t A_out[MATRIX_SIZE][MATRIX_SIZE]
 53|) {
 54|    #pragma HLS INLINE off
 55|    
 56|    // Create U^H (conjugate transpose)
 57|    complex_t UH[MATRIX_SIZE][MATRIX_SIZE];
 58|    #pragma HLS ARRAY_PARTITION variable=UH dim=0 complete
 59|    
 60|    for (int i = 0; i < MATRIX_SIZE; i++) {
 61|        for (int j = 0; j < MATRIX_SIZE; j++) {
 62|            #pragma HLS PIPELINE II=1
 63|            UH[i][j] = complex_conj(U[j][i]);
 64|        }
 65|    }
 66|    
 67|    // temp = A * U
 68|    matrix_mult(A, U, temp);
 69|    
 70|    // A_out = U^H * temp
 71|    matrix_mult(UH, temp, A_out);
 72|}
 73|
 74|void kernel_top(
 75|    const ap_int<TOTAL_BITS> matrix_real_in[MATRIX_SIZE * MATRIX_SIZE],
 76|    const ap_int<TOTAL_BITS> matrix_imag_in[MATRIX_SIZE * MATRIX_SIZE],
 77|    ap_int<TOTAL_BITS> eigenvalues_real_out[MATRIX_SIZE],
 78|    ap_int<TOTAL_BITS> eigenvalues_imag_out[MATRIX_SIZE],
 79|    ap_int<TOTAL_BITS> eigenvectors_real_out[MATRIX_SIZE * MATRIX_SIZE],
 80|    ap_int<TOTAL_BITS> eigenvectors_imag_out[MATRIX_SIZE * MATRIX_SIZE],
 81|    ap_uint<12>& iter_count,
 82|    ap_uint<32>& cycles
 83|) {
 84|    // Interface pragmas
 85|    #pragma HLS INTERFACE mode=m_axi port=matrix_real_in bundle=gmem0 depth=100
 86|    #pragma HLS INTERFACE mode=m_axi port=matrix_imag_in bundle=gmem1 depth=100
 87|    #pragma HLS INTERFACE mode=m_axi port=eigenvalues_real_out bundle=gmem2 depth=10
 88|    #pragma HLS INTERFACE mode=m_axi port=eigenvalues_imag_out bundle=gmem3 depth=10
 89|    #pragma HLS INTERFACE mode=m_axi port=eigenvectors_real_out bundle=gmem4 depth=100
 90|    #pragma HLS INTERFACE mode=m_axi port=eigenvectors_imag_out bundle=gmem5 depth=100
 91|    #pragma HLS INTERFACE mode=s_axilite port=iter_count
 92|    #pragma HLS INTERFACE mode=s_axilite port=cycles
 93|    #pragma HLS INTERFACE mode=s_axilite port=return
 94|    
 95|    // Local matrices
 96|    complex_t A[MATRIX_SIZE][MATRIX_SIZE];
 97|    complex_t V[MATRIX_SIZE][MATRIX_SIZE];
 98|    complex_t U[MATRIX_SIZE][MATRIX_SIZE];
 99|    complex_t temp[MATRIX_SIZE][MATRIX_SIZE];
100|    complex_t A_new[MATRIX_SIZE][MATRIX_SIZE];
101|    
102|    #pragma HLS ARRAY_PARTITION variable=A dim=0 complete
103|    #pragma HLS ARRAY_PARTITION variable=V dim=0 complete
104|    #pragma HLS ARRAY_PARTITION variable=U dim=0 complete
105|    
106|    ap_uint<32> cycle_count = 0;
107|    
108|    // Load input matrix A
109|    for (int i = 0; i < MATRIX_SIZE; i++) {
110|        for (int j = 0; j < MATRIX_SIZE; j++) {
111|            #pragma HLS PIPELINE II=1
112|            int idx = i * MATRIX_SIZE + j;
113|            A[i][j].re = int_to_fixed(matrix_real_in[idx]);
114|            A[i][j].im = int_to_fixed(matrix_imag_in[idx]);
115|        }
116|    }
117|    cycle_count += MATRIX_SIZE * MATRIX_SIZE;
118|    
119|    // Initialize V as identity matrix
120|    for (int i = 0; i < MATRIX_SIZE; i++) {
121|        for (int j = 0; j < MATRIX_SIZE; j++) {
122|            #pragma HLS PIPELINE II=1
123|            if (i == j) {
124|                V[i][j].re = 1.0;
125|                V[i][j].im = 0.0;
126|            } else {
127|                V[i][j].re = 0.0;
128|                V[i][j].im = 0.0;
129|            }
130|        }
131|    }
132|    cycle_count += MATRIX_SIZE * MATRIX_SIZE;
133|    
134|    // Jacobi iteration
135|    ap_uint<12> z;
136|    for (z = 0; z < MAX_ITERATIONS; z++) {
137|        #pragma HLS LOOP_TRIPCOUNT min=10 max=100 avg=50
138|        
139|        // Find maximum off-diagonal element
140|        fixed_t off_diag_max = 0;
141|        ap_uint<4> p = 0;
142|        ap_uint<4> q = 1;
143|        
144|        for (int i = 0; i < MATRIX_SIZE; i++) {
145|            for (int j = i + 1; j < MATRIX_SIZE; j++) {
146|                #pragma HLS PIPELINE II=1
147|                fixed_t abs_val = complex_abs(A[i][j]);
148|                if (abs_val > off_diag_max) {
149|                    off_diag_max = abs_val;
150|                    p = i;
151|                    q = j;
152|                }
153|            }
154|        }
155|        cycle_count += (MATRIX_SIZE * (MATRIX_SIZE + 1)) / 2;
156|        
157|        // Check convergence
158|        if (off_diag_max < CONVERGENCE_THRESHOLD) {
159|            break;
160|        }
161|        
162|        // Get pivot elements
163|        complex_t a_pp = A[p][p];
164|        complex_t a_qq = A[q][q];
165|        complex_t a_pq = A[p][q];
166|        
167|        // Calculate rotation parameters
168|        // theta = 0.5 * arctan(2*|a_pq| / (a_pp - a_qq))
169|        // Note: for Hermitian matrices, a_pp and a_qq should be real
170|        fixed_t abs_a_pq = complex_abs(a_pq);
171|        fixed_t diff = a_pp.re - a_qq.re;
172|        
173|        fixed_t theta;
174|        if (hls::abs((float)diff) < 1e-10) {
175|            theta = 0.785398163;  // pi/4 in fixed-point
176|        } else {
177|            float theta_f = 0.5f * hls::atan(2.0f * (float)abs_a_pq / (float)diff);
178|            theta = theta_f;
179|        }
180|        
181|        // phi = -angle(a_pq)
182|        fixed_t phi = -complex_angle(a_pq);
183|        
184|        // Compute sin/cos
185|        fixed_t cos_theta = hls::cos((float)theta);
186|        fixed_t sin_theta = hls::sin((float)theta);
187|        fixed_t cos_phi = hls::cos((float)phi);
188|        fixed_t sin_phi = hls::sin((float)phi);
189|        
190|        cycle_count += 20;  // Estimate for trig operations
191|        
192|        // Build rotation matrix U as identity
193|        for (int i = 0; i < MATRIX_SIZE; i++) {
194|            for (int j = 0; j < MATRIX_SIZE; j++) {
195|                #pragma HLS PIPELINE II=1
196|                if (i == j) {
197|                    U[i][j].re = 1.0;
198|                    U[i][j].im = 0.0;
199|                } else {
200|                    U[i][j].re = 0.0;
201|                    U[i][j].im = 0.0;
202|                }
203|            }
204|        }
205|        
206|        // Set rotation elements
207|        // U[p,p] = cos(theta)
208|        U[p][p].re = cos_theta;
209|        U[p][p].im = 0;
210|        
211|        // U[p,q] = sin(theta) * exp(-j*phi) = sin(theta) * (cos(phi) - j*sin(phi))
212|        U[p][q].re = sin_theta * cos_phi;
213|        U[p][q].im = -sin_theta * sin_phi;
214|        
215|        // U[q,p] = sin(theta) * exp(j*phi) = sin(theta) * (cos(phi) + j*sin(phi))
216|        U[q][p].re = sin_theta * cos_phi;
217|        U[q][p].im = sin_theta * sin_phi;
218|        
219|        // U[q,q] = cos(theta) (corrected from reference bug)
220|        U[q][q].re = cos_theta;
221|        U[q][q].im = 0;
222|        
223|        cycle_count += MATRIX_SIZE * MATRIX_SIZE;
224|        
225|        // Apply rotation: A = U^H * A * U
226|        apply_rotation(A, U, temp, A_new);
227|        
228|        // Copy A_new to A
229|        for (int i = 0; i < MATRIX_SIZE; i++) {
230|            for (int j = 0; j < MATRIX_SIZE; j++) {
231|                #pragma HLS PIPELINE II=1
232|                A[i][j] = A_new[i][j];
233|            }
234|        }
235|        
236|        // Explicitly zero out pivoted elements
237|        A[p][q].re = 0;
238|        A[p][q].im = 0;
239|        A[q][p].re = 0;
240|        A[q][p].im = 0;
241|        
242|        cycle_count += MATRIX_SIZE * MATRIX_SIZE * MATRIX_SIZE * 3;  // Matrix mult estimate
243|        
244|        // Update eigenvectors: V = V * U
245|        matrix_mult(V, U, temp);
246|        for (int i = 0; i < MATRIX_SIZE; i++) {
247|            for (int j = 0; j < MATRIX_SIZE; j++) {
248|                #pragma HLS PIPELINE II=1
249|                V[i][j] = temp[i][j];
250|            }
251|        }
252|        
253|        cycle_count += MATRIX_SIZE * MATRIX_SIZE * MATRIX_SIZE + MATRIX_SIZE * MATRIX_SIZE;
254|    }
255|    
256|    // Extract eigenvalues (diagonal of A)
257|    for (int i = 0; i < MATRIX_SIZE; i++) {
258|        #pragma HLS PIPELINE II=1
259|        eigenvalues_real_out[i] = fixed_to_int(A[i][i].re);
260|        eigenvalues_imag_out[i] = fixed_to_int(A[i][i].im);
261|    }
262|    cycle_count += MATRIX_SIZE;
263|    
264|    // Write eigenvectors
265|    for (int i = 0; i < MATRIX_SIZE; i++) {
266|        for (int j = 0; j < MATRIX_SIZE; j++) {
267|            #pragma HLS PIPELINE II=1
268|            int idx = i * MATRIX_SIZE + j;
269|            eigenvectors_real_out[idx] = fixed_to_int(V[i][j].re);
270|            eigenvectors_imag_out[idx] = fixed_to_int(V[i][j].im);
271|        }
272|    }
273|    cycle_count += MATRIX_SIZE * MATRIX_SIZE;
274|    
275|    iter_count = z;
276|    cycles = cycle_count;
277|}
